// Sidebar.js
import React from 'react';
import './Sidebar.css';

const Sidebar = ({ onSelectionChange, selectedOption }) => {
    const options = [
        { name: 'Stats', id: 'stats' },
        { name: 'Wrapped', id: 'wrapped' },
        { name: 'To add', id: 'to-add' },
        { name: 'To remove', id: 'to-remove' },
        { name: 'To reprice', id: 'to-reprice' },
        { name: 'To promote', id: 'to-promote' },
    ];

    const handleClick = (id) => {
        onSelectionChange(id);
    };

    return (
        <nav className="sidebar">
            <div className="sidebar-header">Billy</div>
            <ul className="menu">
                {options.map(option => (
                    <li
                        key={option.id}
                        className={`menu-item ${selectedOption === option.id ? 'active' : ''}`}
                        onClick={() => handleClick(option.id)}
                    >
                        {option.name}
                    </li>
                ))}
            </ul>
            <div className="sidebar-footer">Footer Content</div>
        </nav>
    );
};

export default Sidebar;
